{
  "type": "QUIZ",
  "lessonText": "Test your knowledge of piano basics with this quiz.",
  "data": {
    "questions": [
      {
        "question": "What is the name of the white keys on the piano?",
        "options": ["Sharps", "Naturals", "Flats", "Octaves"],
        "correctAnswer": 1,
        "explanation": "The white keys are called naturals."
      },
      {
        "question": "How many keys are there on a standard piano?",
        "options": ["76", "88", "61", "49"],
        "correctAnswer": 1,
        "explanation": "A standard piano has 88 keys."
      },
      {
        "question": "Which note is the first note in the musical alphabet?",
        "options": ["C", "A", "E", "G"],
        "correctAnswer": 1,
        "explanation": "The musical alphabet starts with the note A."
      },
      {
        "question": "What does a sharp symbol (#) indicate?",
        "options": ["Play the note lower", "Play the note higher", "Play the note longer", "Play the note softer"],
        "correctAnswer": 1,
        "explanation": "A sharp raises the pitch of a note by a half step."
      }
    ]
  }
}
